local typeBubbleAnimation =typeof(CS.BubbleAnimation)
local typeClickScale = typeof(CS.YXUIClickScale)
--------------------------------------------------------------------------------
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LBubbleStick:LxNodeBase
local LBubbleStick = LxClass("LBubbleStick", LxNodeBase)

LBubbleStick.ROOT = "UIBubbleStick"

function LBubbleStick:LBubbleStick()
    self._bubbleTran = nil                -- 气泡预制体
    self._heroTrans = nil                 -- 英雄的位置
    self._uiCamera = nil                  -- UI摄像机
    self._sceneCamera = nil               -- 场景摄像机
    self._offset = Vector3.New(0, 0, 0) --偏移量
    self._path = "UI/Prefabs/Com"
    self._name = "Bubble"
    self._textPath = "text"
    self._isDetroyed = false
    self._isVisible = true
    self._timer = nil
	self._clickFunc = nil

    ---@type LDisplayPrefab
    self._dpPrefab = nil
end

------------------------------------------------------------------
function LBubbleStick:OnRun(time)
    if not self._bShowing then return end
    if self._delay < time then
        self._bShowing = false
        self:SetVisible(false)
    end
end
------------------------------------------------------------------
function LBubbleStick:IsBubbleTranValid()
    return self._bubbleTran and CS.IsValidObject(self._bubbleTran)
end

function LBubbleStick:InitBubbleRoot()
    local rootCanvas = LGameUI.GetUIFight()
    self._uiCamera = LGameUI.GetUICamera()
    self._sceneCamera = gLGameScene:GetCurrentSceneCamera()

    self._parentTrans = CS.FindTrans(rootCanvas,LBubbleStick.ROOT)
    if (not self._parentTrans) then
        self._parentTrans = CS.NewObject(LBubbleStick.ROOT, rootCanvas)
    end

end

function LBubbleStick:OnLoaded(dp)
    local instanceTrans = dp:GetDisplayTrans()
    if instanceTrans then
        self._bubbleTran = instanceTrans
        self._bubbleAnimation = self._bubbleTran:GetComponent(typeBubbleAnimation)
        if not self._bubbleAnimation then
            self._bubbleAnimation = self._bubbleTran.gameObject:AddComponent(typeBubbleAnimation)
        end
        if self._isWithin ~= nil then
            self._bubbleAnimation.mWithinWin = self._isWithin
        end
        self._text = CS.FindTrans(self._bubbleTran,self._textPath)
        self:OnUpdateHeroTrans()
    end
end

function LBubbleStick:SetPara(para)
    self._isWithin = para.isWithin
    if self._bubbleAnimation then
        self._bubbleAnimation.mWithinWin = self._isWithin
    end
end

function LBubbleStick:OnUpdateHeroTrans()
    if not self:IsBubbleTranValid() then return end

    self._bubbleAnimation:Init(self._heroTrans,self._uiCamera,self._sceneCamera,self._offset)
    self:SetXTextContent(self._text, self._content)
    CS.ShowObject(self._bubbleTran,self._isVisible)

    LxUiHelper.SetTransClick(self._bubbleTran, function ()
        if self._clickFunc then
            self._clickFunc()
        end
    end)

    if self._clickScale then
    	local clickScale = self._bubbleTran:GetComponent(typeClickScale)
    	if not clickScale then
    		clickScale = self._bubbleTran.gameObject:AddComponent(typeClickScale)
    	else
    		clickScale.enabled = true
    	end
    end

end


-----------------------------------------

function LBubbleStick:CreateBubble(prefabName)
    self:InitBubbleRoot()
    if self:IsBubbleTranValid() then
        if not string.isempty(prefabName) and prefabName ~= self._name then
            self:ClearPrefab()
        else
            return
        end
    end

    if not string.isempty(prefabName) then
        self._name = prefabName
    end

    self:ClearPrefab()
    local dpPrefab = LDisplayPrefab:New()
    self._dpPrefab = dpPrefab
    dpPrefab:CreatePrefab(self._parentTrans, self._path, self._name)
    dpPrefab:SetLoadedFunction(function (dp)
        self:OnLoaded(dp)
    end)
    dpPrefab:StartLoad()
end

function LBubbleStick:ClearPrefab()
    if self._dpPrefab then
        self._dpPrefab:Destroy()
        self._dpPrefab = nil
    end
end

function LBubbleStick:DestroyBubble()
    if self._isDetroyed then return end

    self:ClearPrefab()
    LxNodeBase.Dispose(self)
    self._isDetroyed = true
end

function LBubbleStick:SetVisible(isVisible)
    if self._isVisible == isVisible then return end

    self._isVisible = isVisible
    if not self:IsBubbleTranValid() then return end
    CS.ShowObject(self._bubbleTran,isVisible)
end

function LBubbleStick:SetHeroTrans(heroTrans,offset)
    self._heroTrans = heroTrans
    self._offset = offset
    self:OnUpdateHeroTrans()
end

function LBubbleStick:SetContent(str,delay,startTime)
    self._bShowing = true
    self._content = str
    local startTime = startTime or Time.time
    self._delay = delay + startTime
    self:OnUpdateHeroTrans()
end

